import{c as e,bn as r,aU as d,aX as l,m as i,U as h,ag as a,ar as s,az as n,aD as o}from"./chunks/framework.EkwLm6yr.js";const f=JSON.parse('{"title":"天气","description":"","frontmatter":{"order":2},"headers":[],"relativePath":"地图/北俱芦洲/天气.md","filePath":"地图/北俱芦洲/天气.md","lastUpdated":1779731263000}'),c={name:"地图/北俱芦洲/天气.md"};function b(p,t,m,x,_,y){return r(),d("div",null,[...t[0]||(t[0]=[l('<h1 id="天气" tabindex="-1">天气 <a class="header-anchor" href="#天气" aria-label="Permalink to “天气”">​</a></h1><h2 id="小怪掉落" tabindex="-1">小怪掉落 <a class="header-anchor" href="#小怪掉落" aria-label="Permalink to “小怪掉落”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">木类材料</th><th style="text-align:center;">矿类材料</th><th style="text-align:center;">布类材料</th></tr></thead><tbody><tr><td style="text-align:center;">雪莲花</td><td style="text-align:center;">绿磷矿</td><td style="text-align:center;">冰凝缎</td></tr></tbody></table><h2 id="苍梧渊" tabindex="-1">苍梧渊 <a class="header-anchor" href="#苍梧渊" aria-label="Permalink to “苍梧渊”">​</a></h2><h3 id="场景" tabindex="-1">场景 <a class="header-anchor" href="#场景" aria-label="Permalink to “场景”">​</a></h3><p>踩到白雾上一段时间后，白雾会消散一段时间</p><img src="'+i+'" alt="苍梧渊场景" style="zoom:67%;"><h3 id="青霄玉女" tabindex="-1">青霄玉女 <a class="header-anchor" href="#青霄玉女" aria-label="Permalink to “青霄玉女”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>霜雪之舞：舞动长袖，对周身的玩家造成伤害</td></tr><tr><td>寒霜之音：拨动琴弦，一股霜风随着琴音飘出，有冰冻效果</td></tr><tr><td>封霜飘雪：雪花随着颤动的琴弦飘然而下，洒在大地上，霜冻雪封</td></tr><tr><td>冰霜之镜：召唤冰霜之镜，反射伤害</td></tr><tr><td>冰雪之影：召唤冰雪之影，释放霜雪之舞</td></tr></tbody></table><p>掉落道具：奢天防具制作书</p><h2 id="寒山坡" tabindex="-1">寒山坡 <a class="header-anchor" href="#寒山坡" aria-label="Permalink to “寒山坡”">​</a></h2><h3 id="场景-1" tabindex="-1">场景 <a class="header-anchor" href="#场景-1" aria-label="Permalink to “场景”">​</a></h3><p>间歇性吹寒风，使角色向屏幕左侧移动</p><img src="'+h+'" alt="寒山坡场景" style="zoom:67%;"><h3 id="小怪" tabindex="-1">小怪 <a class="header-anchor" href="#小怪" aria-label="Permalink to “小怪”">​</a></h3><p>该怪物会给全体怪物释放护盾（霸体加高额减伤），请记住出生位置将其秒杀。</p><img src="'+a+'" alt="寒山坡小怪" style="zoom:80%;"><div class="tip custom-block"><p class="custom-block-title">怡玩手柄</p><p>Tips：使用手柄可以控制该怪物让其<strong>为你添加护盾</strong></p></div><h3 id="辟暑大王" tabindex="-1">辟暑大王 <a class="header-anchor" href="#辟暑大王" aria-label="Permalink to “辟暑大王”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>犀角冲撞：猛地向前冲撞很长一段距离。</td></tr><tr><td>大刀挥砍；挥舞大刀攻击近身的玩家。</td></tr><tr><td>烈日当空；从空中召唤一道烈日，持续数秒，玩家若进入烈日照耀的区域会持续降低生命和魔法</td></tr></tbody></table><h3 id="辟寒大王" tabindex="-1">辟寒大王 <a class="header-anchor" href="#辟寒大王" aria-label="Permalink to “辟寒大王”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>犀角冲撞：猛地向前冲撞很长一段距离</td></tr><tr><td>腾空飞斧；抛掷斧头攻击远处的玩家,之后收回</td></tr><tr><td>寒风瑟瑟；召唤一股寒风刮过，被刮到的玩家会行动迟缓</td></tr></tbody></table><p>掉落道具：奢天武器制作书（第一心法）</p><div class="tip custom-block"><p class="custom-block-title">奢天武器制作书</p><p>辟暑大王、辟寒大王<strong>都会掉落</strong></p></div><h2 id="寒山坡隐藏" tabindex="-1">寒山坡隐藏 <a class="header-anchor" href="#寒山坡隐藏" aria-label="Permalink to “寒山坡隐藏”">​</a></h2><p>攻击左右两侧牛角使其<strong>断裂</strong>，开启<strong>隐藏入口</strong></p><img src="'+s+'" alt="寒山坡隐藏" style="zoom:50%;"><h3 id="辟尘大王" tabindex="-1">辟尘大王 <a class="header-anchor" href="#辟尘大王" aria-label="Permalink to “辟尘大王”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>犀角冲撞：猛地向前冲撞很长一段距离</td></tr><tr><td>奇挞藤击：变长奇挞藤，捅击前方的玩家</td></tr><tr><td>烟尘弥漫：召唤一团遮挡视线的烟尘，持续一段时间（附加效果，使玩家命中和闪避下降）</td></tr></tbody></table><p>掉落道具：奢天武器制作书（第二心法）</p><h2 id="冻天" tabindex="-1">冻天 <a class="header-anchor" href="#冻天" aria-label="Permalink to “冻天”">​</a></h2><h3 id="小怪-1" tabindex="-1">小怪 <a class="header-anchor" href="#小怪-1" aria-label="Permalink to “小怪”">​</a></h3><p>该怪物会给全体怪物释放护盾（霸体加高额减伤），请记住出生位置将其秒杀。</p><img src="'+a+'" alt="寒山坡小怪" style="zoom:80%;"><div class="tip custom-block"><p class="custom-block-title">怡玩手柄</p><p>Tips：使用手柄可以控制该怪物让其<strong>为你添加护盾</strong></p></div><p>该怪物会释放冰弹从空中抛落地，命中会被冰冻；靠近其根部还会被花刺所伤</p><img src="'+n+'" alt="冻天小怪" style="zoom:50%;"><h3 id="天气祖巫" tabindex="-1">天气祖巫 <a class="header-anchor" href="#天气祖巫" aria-label="Permalink to “天气祖巫”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>利爪连舞：挥舞前爪连续攻击前方的玩家</td></tr><tr><td>春回雾暖：召唤一团雾气，雾气可以被打散，玩家站在雾气里命中会下降，BOSS站在雾气里会持续回血</td></tr><tr><td>冬雪严寒：耳朵上的青蛇幻化出一个雪蛇图腾，雪蛇会召唤大雪，若10秒内不被破坏，将冻结全场玩家</td></tr><tr><td>夏阳酷暑：另一只耳朵上的青蛇幻化出一个烈蛇图腾，烈蛇发出烈日的光芒，被光芒笼罩的玩家生命回复、法力回复将下降</td></tr><tr><td>秋风为虐：从远端刮过一阵旱风，吸入BOSS口中，被刮到的玩家生命和法力上限将会下降</td></tr></tbody></table><p>掉落道具：奢天古铃制作书</p><h2 id="法宝" tabindex="-1">法宝 <a class="header-anchor" href="#法宝" aria-label="Permalink to “法宝”">​</a></h2><h3 id="奢天化雪令" tabindex="-1">奢天化雪令 <a class="header-anchor" href="#奢天化雪令" aria-label="Permalink to “奢天化雪令”">​</a></h3><img src="'+o+'" alt="奢天化雪令" style="zoom:50%;"><table tabindex="0"><thead><tr><th style="text-align:center;">被动</th><th style="text-align:center;">属性</th></tr></thead><tbody><tr><td style="text-align:center;">回血</td><td style="text-align:center;">6~8</td></tr><tr><td style="text-align:center;">回魔</td><td style="text-align:center;">3~5</td></tr></tbody></table>',44)])])}const k=e(c,[["render",b]]);export{f as __pageData,k as default};
